package helper

import (
	"fmt"
	"strings"
	"unicode"

	"github.com/iancoleman/strcase"
	"github.com/tableauio/tableau/proto/tableaupb"
	"google.golang.org/protobuf/compiler/protogen"
	"google.golang.org/protobuf/proto"
	"google.golang.org/protobuf/reflect/protoreflect"
	"google.golang.org/protobuf/types/descriptorpb"
)

// GenerateFileHeader writes the auto-generated file header comment block,
// including version info and source path, followed by the "#nullable enable" directive.
// If file is non-nil, the source path (or deprecation notice) is included.
func GenerateFileHeader(gen *protogen.Plugin, file *protogen.File, g *protogen.GeneratedFile, version string) {
	g.P("// <auto-generated>")
	g.P("// Code generated by protoc-gen-csharp-tableau-loader. DO NOT EDIT.")
	g.P("// versions:")
	g.P("// - protoc-gen-csharp-tableau-loader v", version)
	g.P("// - protoc                           ", protocVersion(gen))
	if file != nil {
		if file.Proto.GetOptions().GetDeprecated() {
			g.P("// ", file.Desc.Path(), " is a deprecated file.")
		} else {
			g.P("// source: ", file.Desc.Path())
		}
	}
	g.P("// </auto-generated>")
	g.P("#nullable enable")
}

// protocVersion returns the protoc compiler version string (e.g. "v3.19.3")
// extracted from the code generator request. Returns "(unknown)" if not available.
func protocVersion(gen *protogen.Plugin) string {
	v := gen.Request.GetCompilerVersion()
	if v == nil {
		return "(unknown)"
	}
	var suffix string
	if s := v.GetSuffix(); s != "" {
		suffix = "-" + s
	}
	return fmt.Sprintf("v%d.%d.%d%s", v.GetMajor(), v.GetMinor(), v.GetPatch(), suffix)
}

// ParseIndexFieldName returns the C# property name for an index field descriptor.
// It delegates to ParseCsharpPropertyName to match protoc's C# naming convention.
func ParseIndexFieldName(fd protoreflect.FieldDescriptor) string {
	return ParseCsharpPropertyName(fd)
}

// underscoresToCamelCase converts a protobuf-style identifier to CamelCase,
// matching the behavior of protoc's C# code generator.
//
// Rules:
//   - Letters are passed through; the first letter is capitalized or lowercased
//     based on capNextLetter.
//   - Digits are passed through and cause the next letter to be capitalized.
//   - Underscores and other special characters are stripped and cause the next
//     letter to be capitalized.
//   - Periods are preserved if preservePeriod is true (used for namespace
//     conversion); otherwise they are treated like underscores.
//   - Returns "_" if the result would be empty.
//
// Refer: https://github.com/protocolbuffers/protobuf/blob/v3.19.3/src/google/protobuf/compiler/csharp/csharp_helpers.cc#L143
func underscoresToCamelCase(input string, capNextLetter bool, preservePeriod bool) string {
	var result strings.Builder

	for i, c := range input {
		if c >= 'a' && c <= 'z' {
			if capNextLetter {
				result.WriteRune(unicode.ToUpper(c))
			} else {
				result.WriteRune(c)
			}
			capNextLetter = false
		} else if c >= 'A' && c <= 'Z' {
			if i == 0 && !capNextLetter {
				result.WriteRune(unicode.ToLower(c))
			} else {
				result.WriteRune(c)
			}
			capNextLetter = false
		} else if c >= '0' && c <= '9' {
			result.WriteRune(c)
			capNextLetter = true
		} else {
			capNextLetter = true
			if c == '.' && preservePeriod {
				result.WriteRune('.')
			}
		}
	}

	if result.Len() == 0 {
		return "_"
	}
	return result.String()
}

// ParseCsharpPropertyName converts a protobuf field descriptor to the corresponding
// C# property name, matching the behavior of protoc's C# code generator.
// When the PascalCase field name collides with its containing type name,
// "Types", or "Descriptor", a trailing underscore is appended to avoid conflicts.
// See: protobuf/src/google/protobuf/compiler/csharp/csharp_helpers.cc GetPropertyName()
func ParseCsharpPropertyName(fd protoreflect.FieldDescriptor) string {
	propertyName := underscoresToCamelCase(string(fd.Name()), true, false)
	containingName := string(fd.Parent().(protoreflect.MessageDescriptor).Name())
	if propertyName == containingName || propertyName == "Types" || propertyName == "Descriptor" {
		propertyName += "_"
	}
	return propertyName
}

// ParseIndexFieldNameAsKeyStructFieldName returns the CamelCase field name
// used in a generated key struct. For list fields, the name is taken from the
// tableau field option; for other fields, the protobuf field name is used.
// Unlike ParseCsharpPropertyName, this does NOT apply protoc's conflict
// resolution suffix because key structs are user-defined, not protobuf-generated.
func ParseIndexFieldNameAsKeyStructFieldName(fd protoreflect.FieldDescriptor) string {
	if fd.IsList() {
		opts := fd.Options().(*descriptorpb.FieldOptions)
		fdOpts := proto.GetExtension(opts, tableaupb.E_Field).(*tableaupb.FieldOptions)
		return strcase.ToCamel(fdOpts.GetName())
	}
	// NOTE: Do not use ParseCsharpPropertyName here, because key struct field names
	// are defined in our own code (not protobuf-generated), so they are not subject
	// to protoc's property name conflict resolution (appending "_" suffix).
	return strcase.ToCamel(string(fd.Name()))
}

// ParseIndexFieldNameAsFuncParam returns a safe lowerCamelCase function
// parameter name derived from the index field's key struct field name.
// The result is escaped to avoid C# keyword conflicts and invalid identifiers.
func ParseIndexFieldNameAsFuncParam(fd protoreflect.FieldDescriptor) string {
	return escapeIdentifier(strcase.ToLowerCamel(ParseIndexFieldNameAsKeyStructFieldName(fd)))
}

// ParseCsharpType converts a FieldDescriptor to C# type string.
func ParseCsharpType(fd protoreflect.FieldDescriptor) string {
	switch fd.Kind() {
	case protoreflect.BoolKind:
		return "bool"
	case protoreflect.EnumKind:
		fullname := string(fd.Enum().FullName())
		seps := strings.Split(fullname, ".")
		seps[0] = strcase.ToCamel(seps[0])
		for i := 2; i < len(seps); i++ {
			seps[i] = "Types." + seps[i]
		}
		return strings.Join(seps, ".")
	case protoreflect.Int32Kind, protoreflect.Sint32Kind, protoreflect.Sfixed32Kind:
		return "int"
	case protoreflect.Uint32Kind, protoreflect.Fixed32Kind:
		return "uint"
	case protoreflect.Int64Kind, protoreflect.Sint64Kind, protoreflect.Sfixed64Kind:
		return "long"
	case protoreflect.Uint64Kind, protoreflect.Fixed64Kind:
		return "ulong"
	case protoreflect.FloatKind:
		return "float"
	case protoreflect.DoubleKind:
		return "double"
	case protoreflect.StringKind, protoreflect.BytesKind:
		return "string"
	case protoreflect.MessageKind:
		return ParseCsharpClassType(fd.Message())
	// case protoreflect.GroupKind:
	// 	return "group"
	default:
		return fmt.Sprintf("<unknown:%d>", fd.Kind())
	}
}

// ParseCsharpClassType returns the fully qualified C# class type for a message
// descriptor, including the namespace prefix and nested type path (using ".Types.").
func ParseCsharpClassType(md protoreflect.MessageDescriptor) string {
	ns := ParseCsharpNamespace(md.ParentFile())
	name := getNestedName(md)
	if ns != "" {
		return ns + "." + name
	}
	return name
}

// getNestedName returns the C# nested type name for a message descriptor.
// For top-level messages, it returns the message name directly. For nested
// messages, it recursively prepends parent names joined by ".Types.".
func getNestedName(md protoreflect.MessageDescriptor) string {
	parent, ok := md.Parent().(protoreflect.MessageDescriptor)
	if ok {
		return getNestedName(parent) + ".Types." + string(md.Name())
	}
	return string(md.Name())
}

// ParseCsharpNamespace returns the C# namespace for a .proto file.
// If the file has an explicit csharp_namespace option, it is returned as-is.
// Otherwise, the protobuf package name is converted to PascalCase with periods
// preserved (e.g. "my.package" becomes "My.Package").
func ParseCsharpNamespace(fd protoreflect.FileDescriptor) string {
	if opts, ok := fd.Options().(*descriptorpb.FileOptions); ok && opts != nil {
		if ns := opts.GetCsharpNamespace(); ns != "" {
			return ns
		}
	}
	return underscoresToCamelCase(string(fd.Package()), true, true)
}

// ParseOrderedIndexKeyType converts a FieldDescriptor to its treemap key type.
// fd must be an ordered type, or a message which can be converted to an ordered type.
func ParseOrderedIndexKeyType(fd protoreflect.FieldDescriptor) string {
	switch fd.Kind() {
	case protoreflect.Int32Kind, protoreflect.Sint32Kind, protoreflect.Sfixed32Kind:
		return "int"
	case protoreflect.Uint32Kind, protoreflect.Fixed32Kind:
		return "uint"
	case protoreflect.Int64Kind, protoreflect.Sint64Kind, protoreflect.Sfixed64Kind:
		return "long"
	case protoreflect.Uint64Kind, protoreflect.Fixed64Kind:
		return "ulong"
	case protoreflect.FloatKind:
		return "float"
	case protoreflect.DoubleKind:
		return "double"
	case protoreflect.StringKind:
		return "string"
	case protoreflect.EnumKind:
		fullname := string(fd.Enum().FullName())
		seps := strings.Split(fullname, ".")
		seps[0] = strcase.ToCamel(seps[0])
		for i := 2; i < len(seps); i++ {
			seps[i] = "Types." + seps[i]
		}
		return strings.Join(seps, ".")
	case protoreflect.MessageKind:
		switch fd.Message().FullName() {
		case "google.protobuf.Timestamp", "google.protobuf.Duration":
			return "long"
		default:
		}
		fallthrough
	default:
		panic(fmt.Sprintf("unsupported kind: %d", fd.Kind()))
	}
}

// ParseMapFieldNameAsKeyStructFieldName returns the CamelCase field name for
// a map field's key in the generated key struct. If the map value is a message
// type, the first field name of the value message is used; otherwise, the
// tableau field option "key" is used.
func ParseMapFieldNameAsKeyStructFieldName(fd protoreflect.FieldDescriptor) string {
	opts := fd.Options().(*descriptorpb.FieldOptions)
	fdOpts := proto.GetExtension(opts, tableaupb.E_Field).(*tableaupb.FieldOptions)
	name := fdOpts.GetKey()
	if fd.MapValue().Kind() == protoreflect.MessageKind {
		valueFd := fd.MapValue().Message().Fields().Get(0)
		name = string(valueFd.Name())
	}
	return strcase.ToCamel(name)
}

// ParseMapFieldNameAsFuncParam returns a safe lowerCamelCase function parameter
// name for a map field key. Returns an empty string if the key struct field name
// is empty. The result is escaped to avoid C# keyword conflicts.
func ParseMapFieldNameAsFuncParam(fd protoreflect.FieldDescriptor) string {
	fieldName := ParseMapFieldNameAsKeyStructFieldName(fd)
	if fieldName == "" {
		return fieldName
	}
	return escapeIdentifier(fieldName)
}

// ParseMapKeyType returns the C# type string for a map field's key.
func ParseMapKeyType(fd protoreflect.FieldDescriptor) string {
	return ParseCsharpType(fd)
}

// ParseMapValueType returns the C# type string for a map field's value.
func ParseMapValueType(fd protoreflect.FieldDescriptor) string {
	return ParseCsharpType(fd.MapValue())
}

// GetTypeEmptyValue returns the C# default/empty literal for a field's type.
// For example: bool→"false", int→"0", float→"0.0", string→"\"\"", message→"null".
func GetTypeEmptyValue(fd protoreflect.FieldDescriptor) string {
	switch fd.Kind() {
	case protoreflect.BoolKind:
		return "false"
	case protoreflect.Int32Kind, protoreflect.Sint32Kind, protoreflect.Sfixed32Kind,
		protoreflect.Uint32Kind, protoreflect.Fixed32Kind,
		protoreflect.Int64Kind, protoreflect.Sint64Kind, protoreflect.Sfixed64Kind,
		protoreflect.Uint64Kind, protoreflect.Fixed64Kind, protoreflect.EnumKind:
		return "0"
	case protoreflect.FloatKind, protoreflect.DoubleKind:
		return "0.0"
	case protoreflect.StringKind:
		return `""`
	case protoreflect.BytesKind, protoreflect.MessageKind:
		return "null"
	// case protoreflect.GroupKind:
	// 	return "group"
	default:
		return fmt.Sprintf("<unknown:%d>", fd.Kind())
	}
}

// ParseLeveledMapPrefix returns a prefix string used to distinguish nested map
// levels in generated code. For message-typed map values, it derives the prefix
// from the local proto name path (dots replaced with underscores). For scalar
// map values, it returns the kind string (e.g. "string", "int32").
func ParseLeveledMapPrefix(md protoreflect.MessageDescriptor, mapFd protoreflect.FieldDescriptor) string {
	if mapFd.MapValue().Kind() == protoreflect.MessageKind {
		localMsgProtoName := strings.TrimPrefix(string(mapFd.MapValue().Message().FullName()), string(md.FullName())+".")
		return strings.ReplaceAll(localMsgProtoName, ".", "_")
	}
	return mapFd.MapValue().Kind().String()
}

// MapKey represents a single key component in a map or composite index,
// holding the C# type, parameter name, original field name, and the
// associated protobuf field descriptor.
type MapKey struct {
	Type      string                       // C# type string (e.g. "int", "string")
	Name      string                       // parameter/variable name in generated code
	FieldName string                       // original field name (multi-column index only)
	Fd        protoreflect.FieldDescriptor // the map field descriptor this key belongs to
}

// MapKeySlice is an ordered collection of MapKey entries, providing methods
// to build function parameters, arguments, and custom formatted strings
// for code generation.
type MapKeySlice []MapKey

// AddMapKey appends a new MapKey to the slice. If the new key has no name,
// a default name "keyN" is assigned (where N is the new length). If the name
// conflicts with an existing key, a numeric suffix is appended to resolve it.
func (s MapKeySlice) AddMapKey(newKey MapKey) MapKeySlice {
	if newKey.Name == "" {
		newKey.Name = fmt.Sprintf("key%d", len(s)+1)
	}
	for _, key := range s {
		if key.Name == newKey.Name {
			// rewrite to avoid name confict
			newKey.Name = fmt.Sprintf("%s%d", newKey.Name, len(s)+1)
			break
		}
	}
	return append(s, newKey)
}

// GenGetParams generates function parameters, which are the names listed in the function's definition.
func (s MapKeySlice) GenGetParams() string {
	return s.GenCustom(func(key MapKey) string { return key.Type + " " + key.Name }, ", ")
}

// GenGetArguments generates function arguments, which are the real values passed to the function.
func (s MapKeySlice) GenGetArguments() string {
	return s.GenCustom(func(key MapKey) string { return key.Name }, ", ")
}

// GenCustom generates a string by applying fn to each MapKey and joining
// the results with the given separator. Returns an empty string for empty slices.
func (s MapKeySlice) GenCustom(fn func(MapKey) string, sep string) string {
	var params []string
	for _, key := range s {
		params = append(params, fn(key))
	}
	return strings.Join(params, sep)
}

// Indent returns a string of 4*depth spaces, used for indenting generated
// C# code blocks at the specified nesting depth.
func Indent(depth int) string {
	return strings.Repeat("    ", depth)
}
